I'll help create discriminated union types for these financing options. Here's how we can structure it:

```typescript
// Common types used across all options
type Cloud$ProductCategory = 'pv' | 'battery' | 'ev_charger' | 'heat_pump' | 'other' | 'all';

type Cloud$Subsidy = {
  amount: number;
  amount_currency: string;
  slug: string;
  display_name: string;
};

type Cloud$BaseFinancingGroup = {
  purchase_model_code: string;
  product_category: Cloud$ProductCategory;
  total_gross_price: number;
  total_gross_price_unmodified: number;
  discounts: Array<Cloud$ShoppingCartDiscount>;
};

// Product specific data types
type Cloud$ProductData = Cloud$BaseFinancingGroup;

type Cloud$LeasingProductData = Cloud$ProductData & {
  monthly_leasing_gross_price: number;
};

// Base financing option type
type Cloud$BaseFinancingOption = {
  product_category: Cloud$ProductCategory;
  total_gross_price: number;
  total_gross_price_unmodified: number;
  discounts: Array<Cloud$ShoppingCartDiscount>;
  total_net_price: number;
  subsidy: Cloud$Subsidy | null;
  pv_data: Cloud$ProductData | Cloud$LeasingProductData | null;
  battery_data: Cloud$ProductData | null;
  ev_charger_data: Cloud$ProductData | null;
  other_data: Cloud$ProductData | null;
  groups: Array<Cloud$BaseFinancingGroup | Cloud$LeasingFinancingGroup>;
};

// Specific financing option types
type Cloud$BuyNowFinancingOption = Cloud$BaseFinancingOption & {
  purchase_model_code: 'NOW';
};

type Cloud$LoanFinancingOption = Cloud$BaseFinancingOption & {
  purchase_model_code: 'LOAN';
  loan_provider_slug: string;
  loan_provider_name: string;
  loan_interest_basis_points: number;
  loan_num_terms: number;
  monthly_loan_net_price: number;
  monthly_loan_gross_price: number;
  loan_start_balance: number;
  loan_total_amount_payable: number;
};

type Cloud$LeasingFinancingOption = Cloud$BaseFinancingOption & {
  purchase_model_code: 'LEASING';
  leasing_annual_percentage_rate: number;
  leasing_interest_basis_points: number;
  leasing_num_terms: number;
  leasing_subsidy_terms: number;
  monthly_leasing_net_price: number;
  monthly_leasing_gross_price: number;
  split_leasing: boolean;
  split_leasing_num_terms: number;
  split_leasing_last_common_term: number;
  leasing_start_balance: number;
  leasing_total_amount_payable: number;
};

// Combined type
type Cloud$FinancingOption = 
  | Cloud$BuyNowFinancingOption 
  | Cloud$LoanFinancingOption 
  | Cloud$LeasingFinancingOption;

// Type guard functions
function isLoanOption(option: Cloud$FinancingOption): option is Cloud$LoanFinancingOption {
  return option.purchase_model_code === 'LOAN';
}

function isLeasingOption(option: Cloud$FinancingOption): option is Cloud$LeasingFinancingOption {
  return option.purchase_model_code === 'LEASING';
}

function isBuyNowOption(option: Cloud$FinancingOption): option is Cloud$BuyNowFinancingOption {
  return option.purchase_model_code === 'NOW';
}

// Usage examples:
function handleFinancingOption(option: Cloud$FinancingOption) {
  if (isLeasingOption(option)) {
    // TypeScript knows all leasing-specific properties exist here
    console.log(option.monthly_leasing_gross_price);
    console.log(option.leasing_num_terms);
  } else if (isLoanOption(option)) {
